var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"제길, 이 자식 더럽게 끈질기네……!","JPN":"くっそ、しつこいな……！","ENG":"Damn it! He just won't quit...!","TWN":"可惡，這傢伙真是頑固……！"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"탄창은 이게 마지막인가?","JPN":"弾倉はこれが最後か？","ENG":"Is this... the last magazine?","TWN":"彈匣是最後一個了嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"소용없다. 녹색 머리 여자.","JPN":"無駄ダ。緑ノ髪ノ女。","ENG":"It's useless. Green-haired woman.","TWN":"沒用的，綠色頭髮的女人。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"우리는 너희를 모방하고. 학습하며. 진화한다.","JPN":"オレタチハオマエラヲ模倣シ、学習シ、進化スル。","ENG":"We imitate. We learn. We evolve.","TWN":"我們模仿你們，學習你們，進化。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 결국 너희를 포식하지.","JPN":"ソシテ最後ニハオマエラヲ捕食スル。","ENG":"And in the end, we devour you.","TWN":"最後還是會吞噬你們。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"얌전히 내게 먹혀라. 녹색 머리 여자.","JPN":"大人シクオレニ食ワレロ。緑ノ髪ノ女。","ENG":"Let me eat you. Green-haired woman.","TWN":"乖乖地被我吃掉吧，綠發女人。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"먹혀서 그것의 정보를 내놔라.","JPN":"食ワレテ、アレノ情報ヲヨコセ。","ENG":"Be consumed. Offer up what you know.","TWN":"被吞噬了，把它的資訊交出來。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"그리운 근원. 모든 것의 고향.","JPN":"懐カシイ根源。全テノ故郷。","ENG":"The origin. Home of everything.","TWN":"懷念的根源，一切的故鄉。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"세계를 만드는 법칙. 그 나무로부터 내려온 존재.","JPN":"世界ヲ作ル法則。カノ木ヨリ送ラレタ存在。","ENG":"The law of creating a world. The one, descended from the tree.","TWN":"創造世界的規則。從那棵樹上降臨的存在。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"작은 여자가 있는 곳. 넘겨라.","JPN":"小サイ女ノ居場所。ヨコセ。","ENG":"The location where the small girl is. Hand over the info.","TWN":"有小女孩的地方，交出來。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아까부터 무슨 헛소리를 하는 거야!","JPN":"さっきから何言ってんだよ！","ENG":"What nonsense are you even spouting?!","TWN":"從剛才開始，你到底在胡說八道什麼！"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"누굴 찾는지는 몰라도 번지수 잘못 찾았다니까! 내 고향 녀석들은 전부 뒈진 지 오래라고!","JPN":"誰を探してるのか知らないけど、お門違いだって！　私の故郷のやつらは全員死んだんだ！","ENG":"I don't know who you're looking for, but you're asking the wrong person! Everyone from my hometown has been dead for ages!","TWN":"不知道你在找誰，但你找錯地方了！我家鄉的人早就全死光了！"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"큭. 큭. 큭. 큭.","JPN":"クッ。クッ。クッ。クッ。","ENG":"Ke. Ke. Ke. Ke.","TWN":"咳，咳，咳。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"총. 인간의 무기. 여러 번 동포를 죽였지.","JPN":"銃。人間ノ武器。何回モ仲間ヲ殺シタ。","ENG":"Guns. Human weapons. They killed many of my kind.","TWN":"槍。人類的武器。曾多次殺害同胞。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"하지만. 이 정도 위력으로는 나를 죽일 수 없다.","JPN":"シカシ、コノ程度デハ、オレヲ殺セナイ。","ENG":"But. This level of firepower can't kill me.","TWN":"但是，憑這種程度的威力是無法殺死我的。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"잠깐……?","JPN":"おいおい……","ENG":"What...?","TWN":"等一下……?"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"저 녀석, 팔의 형태가……!?","JPN":"あいつ、腕の形態が……！？","ENG":"His arm... it's morphing...?!","TWN":"那傢伙，手臂的形態是……？！"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"받아라. 인간.","JPN":"ココマデダ、人間。","ENG":"Take this. Human.","TWN":"嚐嚐吧！人類。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카! 괜찮아요?","JPN":"ライカ！　大丈夫？","ENG":"Laika! Are you okay?","TWN":"萊卡！你沒事吧？"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"꼬맹이, 네가 안 막아줬으면 골로 갈 뻔했다. 야.","JPN":"ふう。おかげで助かったよ、おこちゃま。","ENG":"If you hadn't blocked that, kid... I'd be toast.","TWN":"小鬼，要不是你擋住了，我差點就完蛋了。嘿。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그보다 방금 봤어? 저 녀석, 방금 카운터 능력 같은 걸 썼다고!","JPN":"それより、今の見た？　あいつ、カウンター能力みたいなやつを使いやがった！","ENG":"Did you see that just now? He just used some kind of ability like that of a Counter!","TWN":"比起這個，你剛才看到了嗎？那傢伙剛才好像使用了制裁者的能力！"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아까도 느꼈지만, 지난 번에 봤을 때보다 훨씬 강해진 것 같아.","JPN":"さっきも思ったけど、前に見た時よりずっと強くなってる気がする。","ENG":"I felt it earlier too, but he's way stronger than the last time we saw him.","TWN":"剛才也感覺到了，好像比上次見到的時候更強了。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"맞아요. 왠지 말투도 달라진 것 같아요.","JPN":"そうね。なんだか喋り方も変わってるみたい。","ENG":"Yeah. Even the way he talks feels different.","TWN":"沒錯，感覺說話的語氣也變了。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};